SECRET_KEY = secrets.token_urlsafe(32)
ALGORITHM = 'HS256'
TOKEN_EXPIRATION_HOURS = 24

def generate_jwt_token(user_id: str, role: str, additional_claims: Optional[Dict[str, Any]] = None) -> str:
    """
    Generate a JWT token for user authentication.
    
    Args:
        user_id: Unique identifier for the user
        role: User's role (e.g., 'admin', 'user', 'guest')
        additional_claims: Optional additional claims to include in the token
    
    Returns:
        JWT token as a string
    """
    if not user_id or not isinstance(user_id, str):
        raise ValueError("user_id must be a non-empty string")
    
    if not role or not isinstance(role, str):
        raise ValueError("role must be a non-empty string")
    
    now = datetime.datetime.utcnow()
    expiration = now + datetime.timedelta(hours=TOKEN_EXPIRATION_HOURS)
    
    payload = {
        'user_id': user_id,
        'role': role,
        'iat': now,
        'exp': expiration,
        'nbf': now,
        'jti': secrets.token_urlsafe(16)
    }
    
    if additional_claims:
        for key in ['user_id', 'role', 'iat', 'exp', 'nbf', 'jti']:
            if key in additional_claims:
                raise ValueError(f"Cannot override reserved claim: {key}")
        payload.update(additional_claims)
    
    token = jwt.encode(payload, SECRET_KEY, algorithm=ALGORITHM)
    
    return token


def verify_jwt_token(token: str) -> Dict[str, Any]:
    """
    Verify and decode a JWT token.
    
    Args:
        token: JWT token string
    
    Returns:
        Decoded token payload
    
    Raises:
        jwt.ExpiredSignatureError: If token has expired
        jwt.InvalidTokenError: If token is invalid
    """
    if not token or not isinstance(token, str):
        raise jwt.InvalidTokenError("Token must be a non-empty string")
    
    try:
        payload = jwt.decode(
            token,
            SECRET_KEY,
            algorithms=[ALGORITHM],
            options={
                'verify_signature': True,
                'verify_exp': True,
                'verify_nbf': True,
                'verify_iat': True,
                'require': ['user_id', 'role', 'exp', 'iat']
            }
        )
        return payload
    except jwt.ExpiredSignatureError:
        raise jwt.ExpiredSignatureError("Token has expired")
    except jwt.InvalidTokenError as e:
        raise jwt.InvalidTokenError(f"Invalid token: {str(e)}")


def token_required(f):
    """
    Decorator to protect routes with JWT authentication.
    """
    @wraps(f)
    def decorated(*args, **kwargs):
        token = None
        
        if 'Authorization' in request.headers:
            auth_header = request.headers['Authorization']
            parts = auth_header.split()
            
